import React, { useState, useEffect } from 'react';
import {
  getAllLocations, getSeatsByLocation, createSeat, updateSeat, deleteSeat,
  createLocation, deleteLocation, getSlotsByEvent, getAllSeatsForSlot,
  getEventsByOrganiser,
} from '../../api/api';
import { useAuth } from '../../context/AuthContext';
import toast from 'react-hot-toast';

const SEAT_TYPE_COLOR = { VIP: 'var(--gold)', PREMIUM: 'var(--blue)', REGULAR: 'var(--text-secondary)' };

const AdminSeatsPage = () => {
  const { user } = useAuth();

  // ── venue + seat state ──────────────────────────────────────────────
  const [locations, setLocations]     = useState([]);
  const [seats, setSeats]             = useState([]);
  const [selectedLoc, setSelectedLoc] = useState(null);
  const [loading, setLoading]         = useState(true);

  // ── slot / booking view state ───────────────────────────────────────
  const [viewMode, setViewMode]       = useState('layout');   // 'layout' | 'bookings'
  const [allSlots, setAllSlots]       = useState([]);         // slots for selected venue
  const [selectedSlot, setSelectedSlot] = useState(null);
  const [seatSlots, setSeatSlots]     = useState([]);         // all seat-slots for selected slot
  const [slotsLoading, setSlotsLoading] = useState(false);
  const [seatsLoading, setSeatsLoading] = useState(false);

  // ── modals ──────────────────────────────────────────────────────────
  const [seatModal, setSeatModal]   = useState(false);
  const [locModal, setLocModal]     = useState(false);
  const [editSeat, setEditSeat]     = useState(null);
  const [saving, setSaving]         = useState(false);
  const [seatForm, setSeatForm]     = useState({ seatNo: '', rowLetter: 'A', seatType: 'REGULAR', basePrice: '' });
  const [locForm, setLocForm]       = useState({ locName: '', address: '', totalSeats: '', facilities: '' });

  // ── load venues ─────────────────────────────────────────────────────
  const loadLocations = async () => {
    try {
      const res  = await getAllLocations();
      const locs = Array.isArray(res.data?.data) ? res.data.data : [];
      setLocations(locs);
      if (locs.length > 0 && !selectedLoc) setSelectedLoc(locs[0]);
    } catch { toast.error('Failed to load venues'); }
    finally { setLoading(false); }
  };

  // ── load seats for venue ────────────────────────────────────────────
  const loadSeats = async (locId) => {
    try {
      const res = await getSeatsByLocation(locId);
      setSeats(Array.isArray(res.data?.data) ? res.data.data : []);
    } catch { setSeats([]); }
  };

  // ── load slots for selected venue (via organiser's events) ──────────
  const loadSlotsForVenue = async (locId) => {
    setSlotsLoading(true);
    setAllSlots([]);
    setSelectedSlot(null);
    setSeatSlots([]);
    try {
      const evRes   = await getEventsByOrganiser(user.userId);
      const events  = evRes.data?.data || [];
      const slotRequests = await Promise.all(
        events.map((e) =>
          getSlotsByEvent(e.eventId).catch(() => ({ data: { data: [] } }))
        )
      );
      const allEventSlots = slotRequests.flatMap((r) => r.data?.data || []);
      // filter by this venue
      const venueSlots = allEventSlots
        .filter((s) => s.location?.locationId === locId)
        .sort((a, b) => new Date(b.showDate) - new Date(a.showDate));
      setAllSlots(venueSlots);
    } catch { toast.error('Failed to load slots'); }
    finally { setSlotsLoading(false); }
  };

  // ── load all seat-slots for a specific show slot ────────────────────
  const loadSeatSlots = async (slotId) => {
    setSeatsLoading(true);
    try {
      const res = await getAllSeatsForSlot(slotId);
      setSeatSlots(Array.isArray(res.data?.data) ? res.data.data : []);
    } catch { toast.error('Failed to load seat status'); setSeatSlots([]); }
    finally { setSeatsLoading(false); }
  };

  useEffect(() => { loadLocations(); }, []);
  useEffect(() => {
    if (selectedLoc) {
      loadSeats(selectedLoc.locationId);
      setViewMode('layout');
      setSelectedSlot(null);
      setSeatSlots([]);
      setAllSlots([]);
    }
  }, [selectedLoc]);

  // when bookings view is activated, load slots
  useEffect(() => {
    if (viewMode === 'bookings' && selectedLoc) {
      loadSlotsForVenue(selectedLoc.locationId);
    }
  }, [viewMode]);

  // when a slot is selected, load its seat statuses
  useEffect(() => {
    if (selectedSlot) loadSeatSlots(selectedSlot.slotId);
  }, [selectedSlot]);

  // ── seat CRUD ───────────────────────────────────────────────────────
  const openCreateSeat = () => {
    setSeatForm({ seatNo: '', rowLetter: 'A', seatType: 'REGULAR', basePrice: '' });
    setEditSeat(null); setSeatModal(true);
  };
  const openEditSeat = (s) => {
    setSeatForm({ seatNo: s.seatNo || '', rowLetter: s.rowLetter || 'A', seatType: s.seatType || 'REGULAR', basePrice: s.basePrice || '' });
    setEditSeat(s); setSeatModal(true);
  };

  const saveSeat = async () => {
    if (!seatForm.seatNo || !seatForm.basePrice) { toast.error('Seat number and price are required'); return; }
    setSaving(true);
    try {
      if (editSeat) { await updateSeat(editSeat.seatId, seatForm); toast.success('Seat updated'); }
      else          { await createSeat(selectedLoc.locationId, seatForm); toast.success('Seat added'); }
      setSeatModal(false);
      loadSeats(selectedLoc.locationId);
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to save seat'); }
    finally { setSaving(false); }
  };

  const delSeat = async (id) => {
    if (!window.confirm('Delete this seat?')) return;
    try { await deleteSeat(id); toast.success('Seat deleted'); loadSeats(selectedLoc.locationId); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed'); }
  };

  // ── venue CRUD ──────────────────────────────────────────────────────
  const saveLocation = async () => {
    if (!locForm.locName || !locForm.address) { toast.error('Venue name and address are required'); return; }
    setSaving(true);
    try {
      await createLocation({ ...locForm, totalSeats: parseInt(locForm.totalSeats) || 0 });
      toast.success('Venue created');
      setLocModal(false);
      setLocForm({ locName: '', address: '', totalSeats: '', facilities: '' });
      loadLocations();
    } catch (err) { toast.error(err.response?.data?.message || 'Failed to create venue'); }
    finally { setSaving(false); }
  };

  const delLocation = async (id) => {
    if (!window.confirm('Delete this venue and all its seats?')) return;
    try { await deleteLocation(id); toast.success('Venue deleted'); setSelectedLoc(null); loadLocations(); }
    catch (err) { toast.error(err.response?.data?.message || 'Failed to delete venue'); }
  };

  // ── derived: rows for layout view ───────────────────────────────────
  const rows = {};
  seats.forEach((s) => { const r = s.rowLetter || 'A'; if (!rows[r]) rows[r] = []; rows[r].push(s); });

  // ── derived: seat status map for bookings view ───────────────────────
  // seatId → SeatSlot (has availability: AVAILABLE | BOOKED | LOCKED)
  const seatStatusMap = {};
  seatSlots.forEach((ss) => { if (ss.seat?.seatId) seatStatusMap[ss.seat.seatId] = ss; });

  const bookedCount   = seatSlots.filter((ss) => ss.availability === 'BOOKED').length;
  const availableCount = seatSlots.filter((ss) => ss.availability === 'AVAILABLE').length;
  const totalCount    = seatSlots.length;

  // ── slot status badge ────────────────────────────────────────────────
  const slotStatusClass = { AVAILABLE: 'badge-success', HOUSEFULL: 'badge-warning', CANCELLED: 'badge-danger' };

  return (
    <div className="container page-content" style={{ background: 'var(--bg-secondary)', minHeight: '100vh', paddingLeft: '28px', paddingRight: '28px' }}>

      {/* ── Page Header ── */}
      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
        <div>
          <h1 className="page-title">SEAT MANAGEMENT</h1>
          <p className="page-subtitle">Manage venues, seat layouts and booking status</p>
        </div>
        <div style={{ display: 'flex', gap: '10px' }}>
          <button onClick={() => setLocModal(true)} className="btn btn-secondary">➕ Add Venue</button>
          {selectedLoc && viewMode === 'layout' && (
            <button onClick={openCreateSeat} className="btn btn-primary">💺 Add Seat</button>
          )}
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '260px 1fr', gap: '24px', alignItems: 'flex-start' }}>

        {/* ── Venues Sidebar ── */}
        <div>
          <div style={{ fontSize: '11px', fontWeight: 700, letterSpacing: '1px', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: '10px' }}>
            Venues
          </div>
          {loading ? (
            <div className="loading-center" style={{ padding: '20px' }}><div className="spinner" /></div>
          ) : (
            <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
              {locations.map((l) => (
                <div
                  key={l.locationId}
                  onClick={() => setSelectedLoc(l)}
                  className="card"
                  style={{
                    padding: '12px 14px', cursor: 'pointer', transition: 'var(--transition)',
                    borderColor: selectedLoc?.locationId === l.locationId ? 'var(--accent)' : 'var(--border)',
                    background: selectedLoc?.locationId === l.locationId ? 'var(--accent-dim)' : 'var(--bg-card)',
                  }}
                >
                  <div style={{ fontWeight: 600, fontSize: '13px', color: selectedLoc?.locationId === l.locationId ? 'var(--accent)' : 'var(--text-primary)' }}>
                    {l.locName}
                  </div>
                  <div style={{ fontSize: '11px', color: 'var(--text-muted)', marginTop: '2px' }}>{l.address}</div>
                  <div style={{ fontSize: '11px', color: 'var(--text-muted)' }}>Capacity: {l.totalSeats}</div>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* ── Main Content ── */}
        <div>
          {!selectedLoc ? (
            <div className="empty-state">
              <div className="empty-state-icon">📍</div>
              <h3>Select a Venue</h3>
            </div>
          ) : (
            <>
              {/* Venue info bar */}
              <div className="card" style={{ padding: '16px 20px', marginBottom: '16px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: '12px' }}>
                <div>
                  <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.3rem' }}>{selectedLoc.locName}</div>
                  <div style={{ fontSize: '13px', color: 'var(--text-secondary)' }}>
                    📍 {selectedLoc.address} &nbsp;·&nbsp; {seats.length} seats configured
                  </div>
                  {selectedLoc.facilities && (
                    <div style={{ fontSize: '12px', color: 'var(--text-muted)', marginTop: '2px' }}>✨ {selectedLoc.facilities}</div>
                  )}
                </div>
                <button onClick={() => delLocation(selectedLoc.locationId)} className="btn btn-danger btn-sm">
                  Delete Venue
                </button>
              </div>

              {/* ── View Mode Toggle ── */}
              <div style={{ display: 'flex', gap: '8px', marginBottom: '20px' }}>
                <button
                  onClick={() => setViewMode('layout')}
                  className="btn"
                  style={{
                    background: viewMode === 'layout' ? 'var(--accent)' : 'var(--bg-card)',
                    color: viewMode === 'layout' ? '#fff' : 'var(--text-secondary)',
                    border: '1.5px solid',
                    borderColor: viewMode === 'layout' ? 'var(--accent)' : 'var(--border)',
                    boxShadow: viewMode === 'layout' ? 'var(--shadow-accent)' : 'var(--shadow-sm)',
                  }}
                >
                  💺 Seat Layout
                </button>
                <button
                  onClick={() => setViewMode('bookings')}
                  className="btn"
                  style={{
                    background: viewMode === 'bookings' ? 'var(--accent)' : 'var(--bg-card)',
                    color: viewMode === 'bookings' ? '#fff' : 'var(--text-secondary)',
                    border: '1.5px solid',
                    borderColor: viewMode === 'bookings' ? 'var(--accent)' : 'var(--border)',
                    boxShadow: viewMode === 'bookings' ? 'var(--shadow-accent)' : 'var(--shadow-sm)',
                  }}
                >
                  📊 Booking Status
                </button>
              </div>

              {/* ════════════════════════════════════════
                  VIEW 1 — SEAT LAYOUT (add/edit/delete)
              ════════════════════════════════════════ */}
              {viewMode === 'layout' && (
                <>
                  {/* Type legend */}
                  <div style={{ display: 'flex', gap: '20px', marginBottom: '16px', flexWrap: 'wrap' }}>
                    {Object.entries(SEAT_TYPE_COLOR).map(([type, color]) => (
                      <span key={type} style={{ fontSize: '12px', color, display: 'flex', alignItems: 'center', gap: '6px' }}>
                        <span style={{ width: 16, height: 16, background: `${color}22`, border: `2px solid ${color}`, borderRadius: '3px', display: 'inline-block' }} />
                        {type}
                      </span>
                    ))}
                  </div>

                  {seats.length === 0 ? (
                    <div className="empty-state">
                      <div className="empty-state-icon">💺</div>
                      <h3>No Seats Added</h3>
                      <button onClick={openCreateSeat} className="btn btn-primary" style={{ marginTop: '16px' }}>Add Seat</button>
                    </div>
                  ) : (
                    <>
                      {/* Visual grid */}
                      <div className="card" style={{ padding: '24px', overflowX: 'auto', marginBottom: '20px' }}>
                        <div style={{ textAlign: 'center', marginBottom: '20px', padding: '8px', background: 'var(--bg-secondary)', borderRadius: '6px', fontSize: '12px', color: 'var(--text-muted)', letterSpacing: '6px', textTransform: 'uppercase', fontWeight: 600 }}>
                          ── SCREEN ──
                        </div>
                        {Object.entries(rows).sort().map(([row, rowSeats]) => (
                          <div key={row} style={{ display: 'flex', gap: '6px', alignItems: 'center', marginBottom: '8px' }}>
                            <span style={{ width: '20px', fontSize: '12px', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)', textAlign: 'center', flexShrink: 0 }}>{row}</span>
                            {rowSeats.sort((a, b) => a.seatNo - b.seatNo).map((s) => {
                              const c = SEAT_TYPE_COLOR[s.seatType] || 'var(--text-muted)';
                              return (
                                <button
                                  key={s.seatId}
                                  title={`${s.rowLetter}${s.seatNo} | ${s.seatType} | ₹${s.basePrice}`}
                                  onClick={() => openEditSeat(s)}
                                  style={{ width: '36px', height: '32px', borderRadius: '5px 5px 2px 2px', border: `2px solid ${c}`, background: `${c}15`, color: c, fontSize: '10px', fontWeight: 600, cursor: 'pointer', transition: 'var(--transition)', fontFamily: 'var(--font-mono)' }}
                                  onMouseEnter={(e) => (e.currentTarget.style.background = `${c}35`)}
                                  onMouseLeave={(e) => (e.currentTarget.style.background = `${c}15`)}
                                >{s.seatNo}</button>
                              );
                            })}
                          </div>
                        ))}
                      </div>

                      {/* Seat table */}
                      <div className="table-wrap">
                        <table>
                          <thead>
                            <tr><th>Seat</th><th>Row</th><th>Type</th><th>Base Price</th><th>Actions</th></tr>
                          </thead>
                          <tbody>
                            {[...seats].sort((a, b) => (a.rowLetter + a.seatNo).localeCompare(b.rowLetter + b.seatNo)).map((s) => (
                              <tr key={s.seatId}>
                                <td style={{ fontFamily: 'var(--font-mono)', fontWeight: 600 }}>{s.rowLetter}{s.seatNo}</td>
                                <td>{s.rowLetter}</td>
                                <td><span style={{ color: SEAT_TYPE_COLOR[s.seatType], fontSize: '12px', fontWeight: 600 }}>{s.seatType}</span></td>
                                <td>₹{parseFloat(s.basePrice).toFixed(2)}</td>
                                <td>
                                  <div style={{ display: 'flex', gap: '6px' }}>
                                    <button onClick={() => openEditSeat(s)} className="btn btn-secondary btn-sm">Edit</button>
                                    <button onClick={() => delSeat(s.seatId)} className="btn btn-danger btn-sm">Del</button>
                                  </div>
                                </td>
                              </tr>
                            ))}
                          </tbody>
                        </table>
                      </div>
                    </>
                  )}
                </>
              )}

              {/* ════════════════════════════════════════
                  VIEW 2 — BOOKING STATUS per slot
              ════════════════════════════════════════ */}
              {viewMode === 'bookings' && (
                <>
                  {slotsLoading ? (
                    <div className="loading-center"><div className="spinner" /><span>Loading shows...</span></div>
                  ) : allSlots.length === 0 ? (
                    <div className="empty-state">
                      <div className="empty-state-icon">📅</div>
                      <h3>No Shows at this Venue</h3>
                      <p style={{ fontSize: '13px' }}>Create a show slot for this venue first</p>
                    </div>
                  ) : (
                    <div style={{ display: 'grid', gridTemplateColumns: '240px 1fr', gap: '20px', alignItems: 'flex-start' }}>

                      {/* Slot list */}
                      <div>
                        <div style={{ fontSize: '11px', fontWeight: 700, letterSpacing: '1px', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: '10px' }}>
                          Select Show
                        </div>
                        <div style={{ display: 'flex', flexDirection: 'column', gap: '6px' }}>
                          {allSlots.map((slot) => (
                            <div
                              key={slot.slotId}
                              onClick={() => setSelectedSlot(slot)}
                              className="card"
                              style={{
                                padding: '12px 14px', cursor: 'pointer', transition: 'var(--transition)',
                                borderColor: selectedSlot?.slotId === slot.slotId ? 'var(--accent)' : 'var(--border)',
                                background: selectedSlot?.slotId === slot.slotId ? 'var(--accent-dim)' : 'var(--bg-card)',
                              }}
                            >
                              <div style={{ fontWeight: 700, fontSize: '13px', color: selectedSlot?.slotId === slot.slotId ? 'var(--accent)' : 'var(--text-primary)', marginBottom: '3px' }}>
                                {slot.event?.name}
                              </div>
                              <div style={{ fontSize: '12px', color: 'var(--text-secondary)', fontWeight: 500 }}>
                                📅 {slot.showDate}
                              </div>
                              <div style={{ fontSize: '12px', color: 'var(--text-secondary)' }}>
                                ⏰ {slot.startTime?.slice(0, 5)} – {slot.endTime?.slice(0, 5)}
                              </div>
                              <div style={{ marginTop: '6px' }}>
                                <span className={`badge ${slotStatusClass[slot.slotStatus] || 'badge-muted'}`} style={{ fontSize: '10px' }}>
                                  {slot.slotStatus}
                                </span>
                              </div>
                            </div>
                          ))}
                        </div>
                      </div>

                      {/* Seat status grid */}
                      <div>
                        {!selectedSlot ? (
                          <div className="empty-state">
                            <div className="empty-state-icon">🎭</div>
                            <h3>Select a Show</h3>
                            <p style={{ fontSize: '13px' }}>Pick a show from the left to see seat status</p>
                          </div>
                        ) : seatsLoading ? (
                          <div className="loading-center"><div className="spinner" /><span>Loading seat status...</span></div>
                        ) : (
                          <>
                            {/* Stats bar */}
                            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '12px', marginBottom: '20px' }}>
                              <StatBox label="Total Seats" value={totalCount} color="var(--text-primary)" />
                              <StatBox label="Booked" value={bookedCount} color="var(--red)" />
                              <StatBox label="Available" value={availableCount} color="var(--green)" />
                            </div>

                            {/* Legend */}
                            <div style={{ display: 'flex', gap: '20px', marginBottom: '16px', flexWrap: 'wrap' }}>
                              {[
                                ['Available', 'var(--green)', '#fff'],
                                ['Booked',    'var(--red)',   'rgba(185,28,28,0.08)'],
                                ['Locked',    'var(--gold)',  'rgba(201,125,26,0.08)'],
                              ].map(([label, color, bg]) => (
                                <span key={label} style={{ fontSize: '12px', color, fontWeight: 600, display: 'flex', alignItems: 'center', gap: '6px' }}>
                                  <span style={{ width: 18, height: 16, background: bg, border: `2px solid ${color}`, borderRadius: '4px 4px 2px 2px', display: 'inline-block' }} />
                                  {label}
                                </span>
                              ))}
                              {/* seat type colors */}
                              {Object.entries(SEAT_TYPE_COLOR).map(([type, color]) => (
                                <span key={type} style={{ fontSize: '12px', color, fontWeight: 600, display: 'flex', alignItems: 'center', gap: '4px' }}>
                                  <span style={{ width: 8, height: 8, background: color, borderRadius: '50%', display: 'inline-block' }} />
                                  {type}
                                </span>
                              ))}
                            </div>

                            {/* Screen label */}
                            <div style={{ textAlign: 'center', marginBottom: '16px', padding: '8px', background: 'var(--bg-secondary)', borderRadius: '6px', fontSize: '12px', color: 'var(--text-muted)', letterSpacing: '6px', textTransform: 'uppercase', fontWeight: 600 }}>
                              ── SCREEN ──
                            </div>

                            {/* Seat grid with booking status */}
                            <div className="card" style={{ padding: '24px', overflowX: 'auto' }}>
                              {seatSlots.length === 0 ? (
                                <div className="empty-state" style={{ padding: '32px' }}>
                                  <p style={{ fontSize: '13px' }}>No seat data for this slot</p>
                                </div>
                              ) : (() => {
                                // group seatSlots by row
                                const slotRows = {};
                                seatSlots.forEach((ss) => {
                                  const r = ss.seat?.rowLetter || 'A';
                                  if (!slotRows[r]) slotRows[r] = [];
                                  slotRows[r].push(ss);
                                });
                                return Object.entries(slotRows).sort().map(([row, rowSeatSlots]) => (
                                  <div key={row} style={{ display: 'flex', gap: '6px', alignItems: 'center', marginBottom: '8px' }}>
                                    <span style={{ width: '20px', fontSize: '12px', color: 'var(--text-muted)', fontFamily: 'var(--font-mono)', textAlign: 'center', flexShrink: 0, fontWeight: 600 }}>{row}</span>
                                    {rowSeatSlots
                                      .sort((a, b) => (a.seat?.seatNo || 0) - (b.seat?.seatNo || 0))
                                      .map((ss) => {
                                        const isBooked  = ss.availability === 'BOOKED';
                                        const isLocked  = ss.availability === 'LOCKED';
                                        const typeColor = SEAT_TYPE_COLOR[ss.seat?.seatType] || 'var(--text-secondary)';

                                        // colour logic
                                        let bg, border, textColor, cursor;
                                        if (isBooked) {
                                          bg = 'rgba(185,28,28,0.1)'; border = 'var(--red)'; textColor = 'var(--red)'; cursor = 'not-allowed';
                                        } else if (isLocked) {
                                          bg = 'rgba(201,125,26,0.1)'; border = 'var(--gold)'; textColor = 'var(--gold)'; cursor = 'not-allowed';
                                        } else {
                                          bg = `${typeColor}15`; border = typeColor; textColor = typeColor; cursor = 'default';
                                        }

                                        return (
                                          <div key={ss.seatSlotId} style={{ position: 'relative' }}>
                                            <button
                                              disabled
                                              title={`${ss.seat?.rowLetter}${ss.seat?.seatNo} | ${ss.seat?.seatType} | ₹${ss.price} | ${ss.availability}`}
                                              style={{
                                                width: '36px', height: '32px',
                                                borderRadius: '5px 5px 2px 2px',
                                                border: `2px solid ${border}`,
                                                background: bg,
                                                color: textColor,
                                                fontSize: '10px', fontWeight: 700,
                                                cursor, fontFamily: 'var(--font-mono)',
                                                opacity: isBooked || isLocked ? 1 : 0.85,
                                                position: 'relative',
                                              }}
                                            >
                                              {ss.seat?.seatNo}
                                              {/* booked overlay cross */}
                                              {isBooked && (
                                                <span style={{ position: 'absolute', top: '1px', right: '2px', fontSize: '8px', color: 'var(--red)', fontWeight: 900, lineHeight: 1 }}>✕</span>
                                              )}
                                            </button>
                                          </div>
                                        );
                                      })}
                                  </div>
                                ));
                              })()}
                            </div>

                            {/* Booked seats detail table */}
                            {bookedCount > 0 && (
                              <div style={{ marginTop: '20px' }}>
                                <h3 style={{ fontFamily: 'var(--font-display)', fontSize: '1.2rem', fontWeight: 400, marginBottom: '12px' }}>
                                  Booked Seats ({bookedCount})
                                </h3>
                                <div className="table-wrap">
                                  <table>
                                    <thead>
                                      <tr><th>Seat</th><th>Type</th><th>Price</th><th>Status</th></tr>
                                    </thead>
                                    <tbody>
                                      {seatSlots
                                        .filter((ss) => ss.availability === 'BOOKED')
                                        .sort((a, b) => (a.seat?.rowLetter + a.seat?.seatNo).localeCompare(b.seat?.rowLetter + b.seat?.seatNo))
                                        .map((ss) => (
                                          <tr key={ss.seatSlotId}>
                                            <td style={{ fontFamily: 'var(--font-mono)', fontWeight: 700 }}>
                                              {ss.seat?.rowLetter}{ss.seat?.seatNo}
                                            </td>
                                            <td>
                                              <span style={{ color: SEAT_TYPE_COLOR[ss.seat?.seatType], fontWeight: 600, fontSize: '12px' }}>
                                                {ss.seat?.seatType}
                                              </span>
                                            </td>
                                            <td>₹{parseFloat(ss.price || 0).toFixed(2)}</td>
                                            <td><span className="badge badge-danger">BOOKED</span></td>
                                          </tr>
                                        ))}
                                    </tbody>
                                  </table>
                                </div>
                              </div>
                            )}
                          </>
                        )}
                      </div>
                    </div>
                  )}
                </>
              )}
            </>
          )}
        </div>
      </div>

      {/* ── Seat Modal ── */}
      {seatModal && (
        <div className="modal-overlay" onClick={() => setSeatModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">{editSeat ? 'EDIT SEAT' : 'ADD SEAT'}</h3>
              <button className="modal-close" onClick={() => setSeatModal(false)}>✕</button>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' }}>
              <div className="form-group">
                <label className="form-label">Seat Number *</label>
                <input className="form-input" value={seatForm.seatNo} onChange={(e) => setSeatForm((f) => ({ ...f, seatNo: e.target.value }))} placeholder="1, 2, 3..." />
              </div>
              <div className="form-group">
                <label className="form-label">Row Letter *</label>
                <input className="form-input" maxLength={1} value={seatForm.rowLetter} onChange={(e) => setSeatForm((f) => ({ ...f, rowLetter: e.target.value.toUpperCase().charAt(0) || 'A' }))} placeholder="A, B, C..." />
              </div>
              <div className="form-group">
                <label className="form-label">Seat Type</label>
                <select className="form-input" value={seatForm.seatType} onChange={(e) => setSeatForm((f) => ({ ...f, seatType: e.target.value }))}>
                  <option value="REGULAR">REGULAR</option>
                  <option value="PREMIUM">PREMIUM</option>
                  <option value="VIP">VIP</option>
                </select>
              </div>
              <div className="form-group">
                <label className="form-label">Base Price (₹) *</label>
                <input type="number" className="form-input" value={seatForm.basePrice} onChange={(e) => setSeatForm((f) => ({ ...f, basePrice: e.target.value }))} placeholder="150" />
              </div>
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button onClick={() => setSeatModal(false)} className="btn btn-secondary" style={{ flex: 1 }}>Cancel</button>
              <button onClick={saveSeat} disabled={saving} className="btn btn-primary" style={{ flex: 2 }}>
                {saving ? 'Saving...' : editSeat ? 'Update Seat' : 'Add Seat'}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ── Venue Modal ── */}
      {locModal && (
        <div className="modal-overlay" onClick={() => setLocModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h3 className="modal-title">ADD VENUE</h3>
              <button className="modal-close" onClick={() => setLocModal(false)}>✕</button>
            </div>
            <div className="form-group">
              <label className="form-label">Venue Name *</label>
              <input className="form-input" value={locForm.locName} onChange={(e) => setLocForm((f) => ({ ...f, locName: e.target.value }))} placeholder="PVR Cinemas, Chennai" />
            </div>
            <div className="form-group">
              <label className="form-label">Address *</label>
              <input className="form-input" value={locForm.address} onChange={(e) => setLocForm((f) => ({ ...f, address: e.target.value }))} placeholder="Full address" />
            </div>
            <div className="form-group">
              <label className="form-label">Total Seating Capacity</label>
              <input type="number" className="form-input" value={locForm.totalSeats} onChange={(e) => setLocForm((f) => ({ ...f, totalSeats: e.target.value }))} placeholder="200" />
            </div>
            <div className="form-group">
              <label className="form-label">Facilities</label>
              <input className="form-input" value={locForm.facilities} onChange={(e) => setLocForm((f) => ({ ...f, facilities: e.target.value }))} placeholder="Parking, AC, Dolby..." />
            </div>
            <div style={{ display: 'flex', gap: '12px' }}>
              <button onClick={() => setLocModal(false)} className="btn btn-secondary" style={{ flex: 1 }}>Cancel</button>
              <button onClick={saveLocation} disabled={saving} className="btn btn-primary" style={{ flex: 2 }}>
                {saving ? 'Saving...' : 'Create Venue'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// ── small stat box component ─────────────────────────────────────────────────
const StatBox = ({ label, value, color }) => (
  <div className="card" style={{ padding: '16px', textAlign: 'center', borderTop: `3px solid ${color}` }}>
    <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.8rem', fontWeight: 400, color }}>{value}</div>
    <div style={{ fontSize: '12px', color: 'var(--text-muted)', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.6px', marginTop: '4px' }}>{label}</div>
  </div>
);

export default AdminSeatsPage;
